+const plaintextMarker = "ENCRYPTION_E2E_CANARY_8f3a2b91"
+
+func generateKey(t *testing.T) []byte {
+	t.Helper()
+	key := make([]byte, encryption.KeySize)
+	if _, err := rand.Read(key); err != nil {
+		t.Fatal(err)
+	}
+	return key
+}
