+// TestIntegration_KeyRotation verifies key rotation works across history entries.
+func TestIntegration_KeyRotation(t *testing.T) {
+	tmpDir := t.TempDir()
+	dataDir := filepath.Join(tmpDir, "data")
+	t.Setenv("XDG_DATA_HOME", dataDir)
+
+	key1 := generateKey(t)
