+		Prompt:    "plaintext prompt",
+		Timestamp: time.Now(),
+		Source:    SourceCLI,
+	}
+	if err := Append(plain); err != nil {
+		t.Fatal(err)
+	}
+
+	// Now enable encryption and write more
+	key := testKey(t)
+	SetEncryptionConfig(&EncryptionConfig{
+		Enabled:     true,
+		EncryptKey:  key,
+		DecryptKeys: [][]byte{key},
+	})
